[{
  "key": "Recommendation",
  "value": "Go to https://console.cloud.google.com/sql/instances/vegangenius-db/overview?project\u003dcomdottasteslikegood and click \"Edit\". Under the \"Database flags\" section, set the \"log_connections\" database flag with the value \"On\"."
},{
  "key": "ExceptionInstructions",
  "value": "Add the security mark \"allow_sql_log_connections_disabled\" to the asset with a value of \"true\" to prevent this finding from being activated again."
},{
  "key": "Explanation",
  "value": "Enabling the \"log_connections\" setting causes each attempted connection to the server to be logged, along with successful completion of client authentication."
},{
