[{
  "key": "Recommendation",
  "value": "Go to https://console.cloud.google.com/sql/instances/vegangenius-db/overview?project\u003dcomdottasteslikegood and click \"Edit\". Under the \"Database flags\" section, set the \"log_disconnections\" database flag with the value \"On\"."
},{
  "key": "ExceptionInstructions",
  "value": "Add the security mark \"allow_sql_log_disconnections_disabled\" to the asset with a value of \"true\" to prevent this finding from being activated again."
},{
  "key": "Explanation",
  "value": "Enabling the \u003cb\u003elog_disconnections\u003c/b\u003e setting creates log entries at the end of each session. The logs are useful in troubleshooting issues and confirming unusual activity across a time period."
},{
