[{
  "key": "Recommendation",
  "value": "Go to https://console.cloud.google.com/sql/instances/vegangenius-db/overview?project\u003dcomdottasteslikegood and click \"Edit\". Under the \"Database flags\" section, set the \"log_duration\" database flag with the value \"on\"."
},{
  "key": "ExceptionInstructions",
  "value": "Add the security mark \"allow_sql_log_duration_disabled\" to the asset with a value of \"true\" to prevent this finding from being activated again."
},{
  "key": "Explanation",
  "value": "The \"log_duration\" flag in this Cloud SQL instance is not set to On. When activated, this setting causes the execution time and duration of each completed statement to be logged. Monitoring the amount of time it takes to execute queries can be crucial in identifying slow queries and troubleshooting database issues."
},{
  "key": "ScannerName",
  "value": "SQL_SCANNER"
},{
