[{
  "key": "Recommendation",
  "value": "Go to the Edit page for this Cloud SQL instance (https://console.cloud.google.com/sql/instances/vegangenius-db/backups?project\u003dcomdottasteslikegood). In the \"Auto backups\" section, select \"Automate backups\", choose a backup window, then click \"Save\"."
},{
  "key": "ExceptionInstructions",
  "value": "Add the security mark \"allow_auto_backup_disabled\" to the asset with a value of \"true\" to prevent this finding from being activated again."
},{
  "key": "Explanation",
  "value": "Automated backups for MySql database instances are disabled."
